    uring_loop: if (builtin.os.tag == .linux) ?IoUringEventLoop else void,

    pub const ClientConnection = struct {
        fd: std.c.fd_t,
        session: ?*Session,
        identified: bool,
        choose_tree_state: ?ChooseTreeState,
