        const pane_count = window.panes.items.len;
        const active_cursor = self.getActiveCursorState(window);

        if (pane_count <= 1) {
            // Single pane: render directly (fast path).
            if (window.active_pane) |pane| {
                if (self.session_loop.getPane(pane.id)) |ps| {
                    ps.renderTo(&out);
