        const ns: i64 = @intCast(timeout_ms * std.time.ns_per_ms);
        const start = gcd.dispatch_time(DISPATCH_TIME_NOW, ns);
        const interval: u64 = if (repeat) @intCast(ns) else DISPATCH_TIME_FOREVER;
